import{_ as a,c as e,a as n,o as i}from"./app-BlID2ROR.js";const t={};function o(c,s){return i(),e("div",null,s[0]||(s[0]=[n(`<h1 id="iiif-tools-src-tools-iiif-js" tabindex="-1"><a class="header-anchor" href="#iiif-tools-src-tools-iiif-js"><span>IIIF Tools (<code>src/tools/iiif.js</code>)</span></a></h1><p>Utility functions for working with IIIF manifests and converting them to MEI format.</p><hr><h2 id="overview" tabindex="-1"><a class="header-anchor" href="#overview"><span>Overview</span></a></h2><p>This module provides helper functions to:</p><ul><li>Convert IIIF manifests to MEI XML</li><li>Validate IIIF manifests</li><li>Extract page arrays from MEI</li><li>Add pages from IIIF canvases to the MEI structure</li></ul><hr><h2 id="functions" tabindex="-1"><a class="header-anchor" href="#functions"><span>Functions</span></a></h2><h3 id="addpage-canvas-canvases-dimension-n-file-meisurfacetemplate-hasitems" tabindex="-1"><a class="header-anchor" href="#addpage-canvas-canvases-dimension-n-file-meisurfacetemplate-hasitems"><span><code>addPage(canvas, canvases, dimension, n, file, meiSurfaceTemplate, hasItems)</code></span></a></h3><p>Adds a page to the MEI structure based on a IIIF canvas.</p><ul><li><strong>Parameters:</strong><ul><li><code>canvas</code>: The IIIF canvas object</li><li><code>canvases</code>: Array of all canvases</li><li><code>dimension</code>: Dimensions of the image</li><li><code>n</code>: Page number</li><li><code>file</code>: File reference or identifier</li><li><code>meiSurfaceTemplate</code>: MEI surface template to use</li><li><code>hasItems</code>: Boolean indicating if the canvas has items</li></ul></li></ul><hr><h3 id="async-getdimension-imgsrc" tabindex="-1"><a class="header-anchor" href="#async-getdimension-imgsrc"><span><code>async getDimension(imgsrc)</code></span></a></h3><p>Fetches and returns the dimensions (width and height) of an image from its IIIF info.json.</p><ul><li><strong>Parameters:</strong><ul><li><code>imgsrc</code>: The IIIF image service URL</li></ul></li></ul><hr><h3 id="async-iiifmanifest2mei-json-url-parser-state" tabindex="-1"><a class="header-anchor" href="#async-iiifmanifest2mei-json-url-parser-state"><span><code>async iiifManifest2mei(json, url, parser, state)</code></span></a></h3><p>Converts a IIIF manifest JSON to an MEI XML document.</p><ul><li><strong>Parameters:</strong><ul><li><code>json</code>: The IIIF manifest JSON object</li><li><code>url</code>: The manifest URL</li><li><code>parser</code>: DOMParser instance</li><li><code>state</code>: Vuex state or context</li></ul></li></ul><hr><h3 id="checkiiifmanifest-json" tabindex="-1"><a class="header-anchor" href="#checkiiifmanifest-json"><span><code>checkIiifManifest(json)</code></span></a></h3><p>Checks if a given JSON object is a valid IIIF manifest.</p><ul><li><strong>Parameters:</strong><ul><li><code>json</code>: The IIIF manifest JSON object</li></ul></li></ul><hr><h3 id="getpagearray-mei" tabindex="-1"><a class="header-anchor" href="#getpagearray-mei"><span><code>getPageArray(mei)</code></span></a></h3><p>Extracts and returns an array of page objects from an MEI XML document.</p><ul><li><strong>Parameters:</strong><ul><li><code>mei</code>: The MEI XML document</li></ul></li></ul><hr><h2 id="example-usage" tabindex="-1"><a class="header-anchor" href="#example-usage"><span>Example Usage</span></a></h2><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code><span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> iiifManifest2mei<span class="token punctuation">,</span> checkIiifManifest<span class="token punctuation">,</span> getPageArray <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@/tools/iiif.js&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Convert IIIF manifest to MEI</span></span>
<span class="line"><span class="token keyword">const</span> mei <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">iiifManifest2mei</span><span class="token punctuation">(</span>manifestJson<span class="token punctuation">,</span> manifestUrl<span class="token punctuation">,</span> parser<span class="token punctuation">,</span> state<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Validate IIIF manifest</span></span>
<span class="line"><span class="token keyword">const</span> isValid <span class="token operator">=</span> <span class="token function">checkIiifManifest</span><span class="token punctuation">(</span>manifestJson<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Get pages from MEI</span></span>
<span class="line"><span class="token keyword">const</span> pages <span class="token operator">=</span> <span class="token function">getPageArray</span><span class="token punctuation">(</span>mei<span class="token punctuation">)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,30)]))}const r=a(t,[["render",o]]),p=JSON.parse('{"path":"/iiif.html","title":"IIIF Tools (src/tools/iiif.js)","lang":"en-US","frontmatter":{},"git":{},"filePathRelative":"iiif.md"}');export{r as comp,p as data};
